#include <memory>
#include <iostream>
#include <vector>

struct Observer {
    virtual ~Observer() = default;
    virtual void notify() = 0;
};

struct Subject {
    void add(std::weak_ptr<Observer> obs) {
        observers.push_back(obs);
    }
    void notifyAll() {
        for (auto& wp : observers) {
            if (auto sp = wp.lock()) {
                sp->notify();
            }
            // إذا انتهت صلاحية Observer، نتجاوزه بسلاسة
        }
    }
    std::vector<std::weak_ptr<Observer>> observers;
};

int main() {
    auto subj = std::make_shared<Subject>();
    auto obs = std::make_shared<Observer>();
    // obs->add(subj); // مثال على الربط
    // عند حذف obs، يصبح weak_ptr منتهيًا
    // notifyAll يتجاوزه بدون bad_weak_ptr
}

