struct ScopedLogger {
    int initial_count;
    ScopedLogger() : initial_count(std::uncaught_exceptions()) {}
    ~ScopedLogger() {
        if (std::uncaught_exceptions() > initial_count) {
            std::cout << "تم طرح استثناء جديد في نطاقي\n";
        } else {
            std::cout << "الخروج الطبيعي\n";
        }
    }
};

int main() {
    ScopedLogger log;
    throw std::runtime_error("خطأ");
}

