#include <exception>
#include <stdexcept>
#include <iostream>
#include <thread>

void worker(std::exception_ptr& result) {
    try {
        throw std::runtime_error("فشل التحميل من الخيط");
    } catch (...) {
        result = std::current_exception();
    }
}

int main() {
    std::exception_ptr eptr;
    std::thread t(worker, std::ref(eptr));
    t.join();

    if (eptr) {
        try {
            std::rethrow_exception(eptr);
        } catch (const std::exception& e) {
            std::cout << "تم التقاط من الخيط الرئيسي: "
                      << e.what();
        }
    }
}

#include <exception>
#include <stdexcept>
#include <iostream>
#include <vector>

int main() {
    std::vector<std::exception_ptr> errors;

    for (int i = 0; i < 3; ++i) {
        try {
            if (i == 1) throw std::runtime_error("خطأ 1");
            if (i == 2) throw std::invalid_argument("خطأ 2");
        } catch (...) {
            errors.push_back(std::current_exception());
        }
    }

    std::cout << "عدد الأخطاء: " << errors.size() << '\n';
    for (auto& eptr : errors) {
        try {
            std::rethrow_exception(eptr);
        } catch (const std::exception& e) {
            std::cout << "- " << e.what() << '\n';
        }
    }
}

#include <exception>
#include <iostream>

int main() {
    std::exception_ptr eptr;
    std::cout << "فارغ: " << !eptr << '\n';

    eptr = std::current_exception();
    // لا يوجد استثناء نشط — يبقى فارغًا
    std::cout << "لا يزال فارغًا: " << !eptr << '\n';

    try {
        throw std::runtime_error("test");
    } catch (...) {
        eptr = std::current_exception();
    }
    std::cout << "يحتوي استثناء: " << !!eptr << '\n';
}

